import React, { useState } from "react";
import "../styles/search.css";

const Search = () => {
  // States to store form inputs
  const [from, setFrom] = useState("");
  const [to, setTo] = useState("");
  const [date, setDate] = useState("");
  const [busList, setBusList] = useState([]);  // To store buses that match the search
  const [currentSearch, setCurrentSearch] = useState(null);

  // Temporary bus data (you can replace it with actual data from 'data.js')
  const busData = [
    { source: "New York", destination: "Los Angeles", busNo: "NY123" },
    { source: "Chicago", destination: "Los Angeles", busNo: "CH456" },
    { source: "New York", destination: "Chicago", busNo: "NY789" },
    { source: "Los Angeles", destination: "New York", busNo: "LA101" }
  ];

  // Function to handle form submission and bus search
  const handleSearch = () => {
    if (!from || !to || !date) {
      alert("Please fill all the fields.");
      return;
    }

    // Create a new search object and update current search state
    const newSearch = { from, to, date };
    setCurrentSearch(newSearch);

    // Filter buses based on source and destination
    const busesFromSearch = busData.filter(
      (bus) => bus.source.toLowerCase() === from.toLowerCase() && bus.destination.toLowerCase() === to.toLowerCase()
    );

    // If buses are found, update the busList state
    if (busesFromSearch.length > 0) {
      setBusList(busesFromSearch);
    } else {
      setBusList([]);
    }

    // Clear form fields
    setFrom("");
    setTo("");
    setDate("");

    // Log the current search data for debugging
    console.log("Stored Search Data: ", newSearch);
    console.log("Available Buses: ", busesFromSearch);
  };

  return (
    <div className="container">
      <div className="search-container">
        {/* Input Fields */}
        <div className="input-box">
          <input
            type="text"
            placeholder="Enter source"
            value={from}
            onChange={(e) => setFrom(e.target.value)}
          />
        </div>
        <div className="input-box">
          <input
            type="text"
            placeholder="Enter destination"
            value={to}
            onChange={(e) => setTo(e.target.value)}
          />
        </div>
        <div className="input-box">
          <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />
        </div>

        {/* Search Button */}
        <button onClick={handleSearch} className="search-btn">Search Buses</button>
      </div>

      {/* Display the result of bus search */}
      <div className="bus-results">
        {busList.length > 0 ? (
          <>
            <h3>Available Buses from {from} to {to}</h3>
            <ul>
              {busList.map((bus, index) => (
                <li key={index}>Bus Number: {bus.busNo}</li>
              ))}
            </ul>
          </>
        ) : (
          <h3>No buses available from {from} to {to}</h3>
        )}
      </div>
    </div>
  );
};

export default Search;
